// ===== 細分化ポジション =====
// 各 sub は1つの大分類(coarse: GK/DF/MF/FW)に属する【不変条件: subGroup(c.sub)===c.pos】
const SUBGROUP={CF:"FW",ST:"FW",LWG:"FW",RWG:"FW",
  OMF:"MF",CMF:"MF",DMF:"MF",LMF:"MF",RMF:"MF",
  LSB:"DF",CB:"DF",RSB:"DF",GK:"GK"};
const SUBS_BY={FW:["CF","ST","LWG","RWG"],MF:["OMF","CMF","DMF","LMF","RMF"],DF:["LSB","CB","RSB"],GK:["GK"]};
// 大分類内の近接クラスタ(同クラスタ内=近接 / 別クラスタ=非近接)
const SUBNEAR={FW:[["CF","ST"],["LWG","RWG"]],
  MF:[["OMF","CMF","DMF"],["LMF","RMF"]],
  DF:[["LSB","RSB"],["CB"]],GK:[["GK"]]};
const SUBLABEL={CF:"CF",ST:"ST",LWG:"LWG",RWG:"RWG",OMF:"OMF",CMF:"CMF",DMF:"DMF",LMF:"LMF",RMF:"RMF",LSB:"LSB",CB:"CB",RSB:"RSB",GK:"GK"};
// 2段階適正 pen: ①大分類 一致/不一致 → ②同分類内の細分 完全一致/近接/非近接
const POSFIT={exact:1.0,near:0.92,far:0.85,group:0.72};
function subGroup(sub){return SUBGROUP[sub]||"MF";}
function subClusterMates(group,sub){const c=(SUBNEAR[group]||[]).find(a=>a.indexOf(sub)>=0);return c||[sub];}
function posFit(cardSub,slotSub){
  const cg=subGroup(cardSub),sg=subGroup(slotSub);
  if(cg!==sg)return POSFIT.group;                                   // ① 大分類が違う(例:MF→FW枠)
  if(cardSub===slotSub)return POSFIT.exact;                         // 細分まで完全一致
  return subClusterMates(sg,slotSub).indexOf(cardSub)>=0?POSFIT.near:POSFIT.far; // ② 同分類内の近接/非近接
}
